class Example {
public:
    void print(int num) {
        std::cout << "Printed integer: " << num << std::endl;
    }

    void print(std::string str) {
        std::cout << "Printed string: " << str << std::endl;
    }
};

int main() {
    Example ex;
    ex.print(5);       // Calls the int version of print
    ex.print("Hello"); // Calls the string version of print
    return 0;
}
```

